#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
typedef long long LL;
typedef __int128 Int;
inline LL read()
{
	LL res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int Mod=998244353,Inv[10]={0,1,499122177,332748118,748683265,598946612,166374059,855638017,873463809,443664157};
inline int qpow(int a,int b=Mod-2){int r(1);while(b)b&1?r=1ll*r*a%Mod:0ll,a=1ll*a*a%Mod,b=b>>1;return r;} int M,K,T;
namespace Sub1 // accept
{
	int dp[15][2]; inline void mian()
	{
		while(T--)
		{
			int n=read(),ans=0;dp[0][1]=1;
			rep(1,n,i)
			{
				dp[i][1]=1ll*Inv[2]*dp[i-1][1]%Mod;
				dp[i][0]=(1ll*Inv[2]*dp[i-1][1]+dp[i-1][0])%Mod;
				ans+=(1ll*dp[i-1][1]*Inv[2]+dp[i-1][0])%Mod;
			}
			printf("%d\n",ans);
		}
	}
}
namespace Sub2 // accept
{
	int idx[9][9],Sz;struct Matrix
	{
		int a[46][46];inline Matrix(){memset(a,0,sizeof(a));}
		inline Matrix operator * (const Matrix &Q)const
		{
			Matrix res;
			rep(0,Sz,i)rep(0,Sz,j)rep(0,Sz,k)res.a[i][j]=(1ll*a[i][k]*Q.a[k][j]+res.a[i][j])%Mod;
			return res;
		}
	}x;
	inline Matrix qpow(Matrix a,LL b)
	{
		Matrix res;rep(0,Sz,i)res.a[i][i]=1;
		while(b){if(b&1)res=res*a;a=a*a;b=b>>1;}return res;
	}
	inline void mian()
	{
		rep(0,K,a)rep(0,K-a,b)idx[a][b]=Sz++;
		rep(0,K,a)rep(0,K-a,b)
		{
			if(a)
			{
				x.a[idx[a-1][b]][idx[a][b]]=1ll*Inv[a+b+1]*a%Mod;
			}
			if(b)
			{
				if(a+b<K)x.a[idx[a+1][b]][idx[a][b]]=1ll*Inv[a+b+1]*b%Mod;
				else x.a[idx[a+1][b-1]][idx[a][b]]=1ll*Inv[a+b+1]*b%Mod;
			}
			x.a[idx[a][b]][idx[a][b]]=Inv[a+b+1];
			x.a[Sz][idx[a][b]]=Inv[a+b+1];
		}
		x.a[Sz][Sz]=1;
		while(T--)
		{
			Matrix p=x; p=qpow(p,read());
			printf("%d\n",p.a[Sz][idx[0][1]]);
		}
	}
}
namespace Sub3 // C=165
{
	int idx[9][9][9],Sz;struct Matrix
	{
		int a[166][166];inline Matrix(){memset(a,0,sizeof(a));}
		inline Matrix operator * (const Matrix &Q)const 
		{
			Matrix res;rep(0,Sz,i)rep(0,Sz,j)
			{
				Int tmp=0;rep(0,Sz,k)tmp+=1ll*a[i][k]*Q.a[k][j];
				res.a[i][j]=tmp%Mod;
			}
			return res;
		}
	}P[61],&x=P[0];
	struct Vector
	{
		int a[166];inline Vector(){memset(a,0,sizeof(a));}
		inline Vector operator * (const Matrix &Q)const
		{
			Vector res;rep(0,Sz,i)
			{
				Int tmp=0;rep(0,Sz,j)tmp+=1ll*a[j]*Q.a[i][j];
				res.a[i]=tmp%Mod;
			}
			return res;
		}
	};
	inline void mian()
	{
		rep(0,K,a)rep(0,K-a,b)rep(0,K-a-b,c)idx[a][b][c]=Sz++;
		rep(0,K,a)rep(0,K-a,b)rep(0,K-a-b,c)
		{
			if(a)
			{
				x.a[idx[a-1][b][c]][idx[a][b][c]]=1ll*Inv[a+b+c+1]*a%Mod;
			}
			if(b)
			{
				if(a+b+c<K)x.a[idx[a+1][b-1][c+1]][idx[a][b][c]]=1ll*Inv[a+b+c+1]*b%Mod;
				else x.a[idx[a+1][b-1][c]][idx[a][b][c]]=1ll*Inv[a+b+c+1]*b%Mod;
			}
			if(c)
			{
				if(a+b+c<K)x.a[idx[a][b+1][c]][idx[a][b][c]]=1ll*Inv[a+b+c+1]*c%Mod;
				else x.a[idx[a][b+1][c-1]][idx[a][b][c]]=1ll*Inv[a+b+c+1]*c%Mod;
			}
			x.a[idx[a][b][c]][idx[a][b][c]]=x.a[Sz][idx[a][b][c]]=Inv[a+b+c+1];
		}
		x.a[Sz][Sz]=1;
		rep(1,60,i)P[i]=P[i-1]*P[i-1];
		while(T--)
		{
			LL n=read();Vector res;res.a[idx[0][0][1]]=1;
			rep(0,60,i)if((n>>i)&1)res=res*P[i];printf("%d\n",res.a[Sz]);
//			rep(0,Sz,i)printf("%d ",res.a[i]);
		}
	}
}
int main()
{
	T=read();M=read();K=read();
	if(M==1)return Sub1::mian(),0;
	if(M==2)return Sub2::mian(),0;
	if(M==3)return Sub3::mian(),0;
}
